// Initialize Discord client with required intents, partials, and ultra-cautious cache limits
const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMembers,
    GatewayIntentBits.GuildMessages,
    GatewayIntentBits.GuildMessageReactions,
    GatewayIntentBits.MessageContent  // Required for message collector (safari import file uploads) - attachments field is empty without this
  ],
  partials: [Partials.Message, Partials.Channel, Partials.Reaction],
  // Cache limits: Only limit MessageManager to prevent unbounded message cache growth
  // GuildMemberManager/UserManager are naturally bounded by server membership
  // NOTE: RoleManager and ChannelManager are NOT limited per Discord.js recommendations
  makeCache: Options.cacheWithLimits({
    MessageManager: 50        // Limit message cache (messages are large objects)
    // GuildMemberManager: REMOVED - caused mid-operation evictions leading to "Supplied parameter is not a User nor a Role" errors
    // UserManager: REMOVED - redundant with member caching, saves memory (6.69MB -> 0.97MB)
  })
});

// ============================================================================
// 📅 SCHEDULER - Register actions for persistent job scheduling
// ============================================================================
scheduler.registerAction('process_round_results', async (payload, schedulerClient) => {
  const { channelId, guildId } = payload;
  try {
    console.log(`⚔️ DEBUG: Executing scheduled Safari round results in channel ${channelId}`);
    const { processRoundResults } = await import('./safariManager.js');
    const roundData = await processRoundResults(guildId, null, schedulerClient, { isScheduled: true, channelId });

    if (roundData === null) {
      console.log(`✅ DEBUG: Scheduled Safari round results executed successfully via webhook`);
      return;
    }

    if (roundData?.data?.content) {
      console.error(`❌ DEBUG: Scheduled execution returned error:`, roundData.data.content);
    }
  } catch (error) {
    console.error(`❌ ERROR: Failed to execute scheduled Safari round results:`, error);
    try {
      const channel = await schedulerClient.channels.fetch(channelId);
      if (channel) {
        const errorWebhook = await channel.createWebhook({
          name: 'Safari Error',
          reason: 'Scheduled Safari error notification'
        });
        await fetch(errorWebhook.url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            content: '❌ **ERROR**: Scheduled Safari round results failed to execute. Please run the command manually.'
          })
        });
        setTimeout(() => errorWebhook.delete().catch(() => {}), 1000);
      }
    } catch (channelError) {
      console.error(`❌ ERROR: Could not send error message to channel:`, channelError);
    }
  }
});

scheduler.registerAction('send_reminder', async (payload, schedulerClient) => {
  const { channelId, reminderMessage } = payload;
  try {
    const channel = await schedulerClient.channels.fetch(channelId);
    if (channel) {
      await channel.send({
        content: `⏰ **Safari Round Results** will be revealed in **${reminderMessage}**! 🦁`,
        flags: 0
      });
    }
  } catch (error) {
    console.error(`❌ ERROR: Failed to send reminder message to channel ${channelId}:`, error);
  }
});

scheduler.registerAction('execute_custom_action', async (payload, schedulerClient) => {
  const { channelId, guildId, actionId, userId, actionName } = payload;
  try {
    console.log(`⏰ [SCHEDULER] Executing Custom Action "${actionName}" (${actionId}) in channel ${channelId}`);
    const channel = await schedulerClient.channels.fetch(channelId);
    const guild = await schedulerClient.guilds.fetch(guildId);

    // Fetch the scheduling user's member for condition evaluation
    let member = null;
    try { member = await guild.members.fetch(userId); } catch (e) {
      console.warn(`⚠️ [SCHEDULER] Could not fetch member ${userId}: ${e.message}`);
    }

    const { executeButtonActions } = await import('./safariManager.js');
    const interactionData = {
      token: null,
      applicationId: process.env.APP_ID,
      client: schedulerClient,
      member,
      user: { id: userId },
      channel: { name: channel.name }
    };

    const result = await executeButtonActions(guildId, actionId, userId, interactionData, schedulerClient);

    // Check if result is an error/failure — don't post errors to the channel
    const isError = result?.content?.startsWith('❌') ||
                    (result?.flags && (result.flags & InteractionResponseFlags.EPHEMERAL));
    if (isError) {
      console.warn(`⚠️ [SCHEDULER] Custom Action "${actionName}" returned error: ${result?.content || 'unknown'}`);
      return; // Don't post error messages to channel via webhook
    }

    // Post successful result to channel via webhook
    const webhook = await channel.createWebhook({
      name: actionName || 'Scheduled Action',
      reason: 'Scheduled custom action execution'
    });

    if (result?.components) {
      // Strip ephemeral flags from components — scheduled results are public
      const flags = result.flags ? (result.flags & ~InteractionResponseFlags.EPHEMERAL) : (1 << 15);
      await fetch(webhook.url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          flags: flags | (1 << 15), // Ensure IS_COMPONENTS_V2
          components: result.components
        })
      });
    } else if (result?.content) {
      await fetch(webhook.url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: result.content })
      });
    }

    setTimeout(() => webhook.delete('Cleanup after scheduled action').catch(() => {}), 5000);
    console.log(`✅ [SCHEDULER] Custom Action "${actionName}" executed in #${channel.name}`);
  } catch (error) {
    console.error(`❌ [SCHEDULER] Custom Action "${actionName}" (${actionId}) failed:`, error);
    try {
      const channel = await schedulerClient.channels.fetch(channelId);
      if (channel) {
        const errorWebhook = await channel.createWebhook({
          name: 'Scheduled Action Error',
          reason: 'Scheduled action error notification'
        });
        await fetch(errorWebhook.url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            content: `❌ **Scheduled Action Failed**: "${actionName}" could not execute. Please run the action manually.`
          })
        });
        setTimeout(() => errorWebhook.delete().catch(() => {}), 1000);
      }
    } catch (channelError) {
      console.error(`❌ [SCHEDULER] Could not send error message to channel:`, channelError);
    }
  }
});

// Add these event handlers after client initialization
client.once('ready', async () => {
  console.log('Discord client is ready!');

  // Set emoji validation client for parseAndValidateEmoji
  const { setEmojiClient } = await import('./utils/emojiUtils.js');
  setEmojiClient(client);

  // Record restart timestamp for health monitoring
  try {
    const { recordRestart } = await import('./src/monitoring/restartTracker.js');
    await recordRestart();
  } catch (err) {
    console.error('Failed to record restart:', err.message);
  }

  // Set Discord client reference for analytics logging
  setDiscordClient(client);

  // PRIORITY 3: Batch all analytics updates, then write ONCE
  console.log('📊 Updating server analytics metadata...');
  const playerData = await loadPlayerData();
  let analyticsUpdated = false;
  let newServersCount = 0;
  let updatedServersCount = 0;
  const newServers = [];
  const updatedServers = [];
  const unchangedServers = [];

  // Collect all metadata updates in memory
  for (const guild of client.guilds.cache.values()) {
    const result = await ensureServerData(guild);

    if (result.updated) {
      analyticsUpdated = true;
      if (result.isNew) {
        newServersCount++;
        newServers.push(guild.name);
        console.log(`🎉 NEW SERVER INSTALLED: ${guild.name} (${guild.id})`);

        // Post new server install announcement to Discord analytics channel
        try {
          const { logNewServerInstall } = await import('./src/analytics/analyticsLogger.js');
          const pdGuild = playerData[guild.id];
          await logNewServerInstall(guild, pdGuild?.ownerInfo || null);
        } catch (error) {
          console.error('Error posting server install announcement:', error);
          // Don't break server initialization if announcement fails
        }
      } else {
        updatedServersCount++;
        updatedServers.push(guild.name);
      }
    } else {
      unchangedServers.push(guild.name);
    }
  }

  // SINGLE WRITE after all updates
  if (analyticsUpdated) {
    await savePlayerData(playerData);
    if (newServersCount > 0) {
      console.log(`✅ Analytics: ${newServersCount} new server(s) installed: ${newServers.join(', ')}`);
    }
    if (updatedServersCount > 0) {
      console.log(`✅ Analytics: ${updatedServersCount} updated: ${updatedServers.join(', ')}`);
    }
  } else {
    console.log(`✅ Analytics: No metadata changes needed (${unchangedServers.length} servers checked: ${unchangedServers.slice(0, 3).join(', ')}${unchangedServers.length > 3 ? ` +${unchangedServers.length - 3} more` : ''})`);
  }

  // Initialize reaction mappings from persistent storage
  console.log('📥 Loading reaction mappings from persistent storage...');
  client.roleReactions = new Map();
  let totalMappingsLoaded = 0;

  for (const guild of client.guilds.cache.values()) {
    // Load reaction mappings for this guild
    try {
      const mappings = await loadAllReactionMappings(guild.id);
      let guildMappingsCount = 0;

      for (const [messageId, mappingData] of Object.entries(mappings)) {
        if (mappingData && mappingData.mapping) {
          client.roleReactions.set(messageId, mappingData.mapping);
          guildMappingsCount++;
        }
      }

      if (guildMappingsCount > 0) {
        console.log(`  ✅ Loaded ${guildMappingsCount} reaction mappings for guild ${guild.name}`);
        totalMappingsLoaded += guildMappingsCount;
      }

      // Clean up old mappings while we're at it
      const cleanedCount = await cleanupOldReactionMappings(guild.id);
      if (cleanedCount > 0) {
        console.log(`  🧹 Cleaned ${cleanedCount} old reaction mappings for guild ${guild.name}`);
      }
    } catch (error) {
      console.error(`  ❌ Error loading reaction mappings for guild ${guild.name}:`, error);
    }
  }

  console.log(`📥 Total reaction mappings loaded: ${totalMappingsLoaded}`);

  // Initialize and restore persistent scheduler
  scheduler.init(client);
  await scheduler.restore();

  // Start PM2 Error Log Monitoring (Dev & Prod)
  const pm2Logger = getPM2ErrorLogger(client);
  pm2Logger.start();

  // Start automated Discord channel backups
  try {
    const { getBackupService } = await import('./src/monitoring/backupService.js');
    const backupService = getBackupService(client);
    const isProduction = process.env.PRODUCTION === 'TRUE';
    backupService.start({
      intervalMs: isProduction ? 24 * 60 * 60 * 1000 : 60 * 60 * 1000, // 24h prod, 1h dev
      targetHourUTC: isProduction ? 10 : null, // Prod: 10:00 UTC = 6PM AWST daily. Dev: simple interval
    });
  } catch (err) {
    console.error('📦 [BACKUP] Failed to start backup service:', err.message);
  }

  // Restore health monitor if previously configured
  try {
    const { getHealthMonitor } = await import('./src/monitoring/healthMonitor.js');
    const monitor = getHealthMonitor(client);
    await monitor.restoreFromConfig();
  } catch (err) {
    console.error('[HealthMonitor] Failed to restore:', err.message);
  }

  // Dev-only: Log test coverage scan
  if (process.env.PRODUCTION !== 'TRUE') {
    try {
      const { logTestCoverage } = await import('./scripts/test-coverage-scan.js');
      logTestCoverage();
    } catch (error) {
      console.log('⚠️ Test coverage scan failed:', error.message);
    }
  }
});

client.on('guildCreate', async (guild) => {
  // PRIORITY 3: Handle new guild, then write once
  const playerData = await loadPlayerData();
  const result = await ensureServerData(guild);

  if (result.updated) {
    await savePlayerData(playerData);
    console.log(`✅ New server data saved: ${guild.name} (${guild.id})`);
  }

  // Log new server install to analytics
  try {
    const { logNewServerInstall } = await import('./src/analytics/analyticsLogger.js');
    await logNewServerInstall(guild, playerData[guild.id]?.ownerInfo || null);
  } catch (error) {
    console.error(`❌ Failed to log server install for ${guild.name}:`, error);
  }

  // Send welcome message using Discord Messenger service
  try {
    const { default: DiscordMessenger } = await import('./discordMessenger.js');
    await DiscordMessenger.sendWelcomePackage(client, guild);
  } catch (error) {
    console.error(`❌ Failed to send welcome message for ${guild.name}:`, error);
    // Don't break the installation process if welcome message fails
  }
});

