        return res.send({
          type: InteractionResponseType.CHANNEL_MESSAGE_WITH_SOURCE,
          data: {
            content: `❌ Error updating stamina settings: ${error.message}`,
            flags: InteractionResponseFlags.EPHEMERAL
          }
        });
