        const button = {
          name: buttonLabel,
          label: buttonLabel,
          description: buttonDesc || '',
          emoji: buttonEmoji,
          style: 1, // Primary
          coordinates: [], // No coordinates initially
          linkedItems: [], // No linked items initially
          actions: [],
          trigger: {
            type: 'button'
          },
          metadata: {
            createdBy: userId,
            lastModified: timestamp,
            usageCount: 0
          }
        };
        
